}

Method.Source:
/// <summary>
/// initialize custom fields from table <c>VendInvoiceInfoLine</c>
/// </summary>
/// <param name = "_vendInvoiceInfoLine">VendInvoiceInfoLine _vendInvoiceInfoLine</param>
void initFromVendInvoiceInfoLine(VendInvoiceInfoLine _vendInvoiceInfoLine)
{
    next initFromVendInvoiceInfoLine(_vendInvoiceInfoLine);
    if(VendParameters::find().ETGEnableTermoNumberFeature == NoYes::Yes)
    {
        this.ETGTermoValueUsageReal = _vendInvoiceInfoLine.LineAmount;
    }

    this.ETGDescriptionOfGoodsServices = _vendInvoiceInfoLine.ETGDescriptionOfGoodsServices;

    if(ETGACFParameters::find().EnablePTBFContractsPurch == NoYes::Yes)
    {
        PurchLine purchlineloc = _vendInvoiceInfoLine.purchLine();

        this.ETGActualLineAmt             = purchlineloc.ETGCrDrJrnAmt;
        this.ETGActualPurchPrice          = purchlineloc.ETGActualPurchPrice;
        this.ETGCrDrNoteCreated           = purchlineloc.ETGCrDrNoteCreated;
        this.ETGJournalNum                = purchlineloc.ETGJournalNum;
        this.ETGCrDrJrnRateCardDiffAmount = _vendInvoiceInfoLine.ETGCrDrJrnRateCardDiffAmount;
        this.ETGActualQuantity            = _vendInvoiceInfoLine.ETGActualQuantity; // Abhinav - 12-02-2025
    }
}
